  ('disabled-7c4986e7-moex-00283', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-110-6948958a', 'sub-disabled-7c4986e7-01', NULL, 'single_choice', '當施打流感疫苗具有外部利益時，下列敘述何者正確？', '["競爭市場是有效率的", "競爭市場的效率太低", "課稅可以改善效率", "施打疫苗應該免費"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:00+00:00", "source_pdf_sha1": "bdee1ccae880", "answer_pdf_sha1": "5625f3fd9f41", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "405", "s": "0910", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
